  ('aboriginal-7fec267e-moex-00134', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-b96fcbef', 'sub-aboriginal-7fec267e-06', NULL, 'essay', '甲授予乙購買一台價金新臺幣（下同）300 萬元以下之休旅車及向 A銀
行貸款 600萬元之代理權限。若乙表明代理意旨，而以甲代理人之名義
向丙購買價金 500 萬元休旅車一台及向 A銀行貸款 600萬元。試問：甲
與丙間、甲與 A銀行間是否成立契約關係？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:00+00:00", "source_pdf_sha1": "e5e1392aeec0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00135', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-b96fcbef', 'sub-aboriginal-7fec267e-06', NULL, 'essay', '甲因隙對乙生恨，某日甲持刀砍殺乙，乙身中數刀受傷倒地後向甲求饒，
甲於是決定放乙一條生路，主動電召救護車。甲躲在現場暗處等待救護
人員，救護人員 10 分鐘內迅速抵達現場將乙送醫救治。惟救護車開往醫
院行經某十字路口時，丙闖紅燈撞上救護車，乙當場傷重不治死亡。事
後鑑定報告指出，儘管乙身受刀傷，但若沒有發生闖紅燈車禍，以乙所
受刀傷程度，若及時抵達醫院救治，乙不會死亡。試問：甲之行為成立
何罪？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:00+00:00", "source_pdf_sha1": "e5e1392aeec0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00136', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-b96fcbef', 'sub-aboriginal-7fec267e-06', NULL, 'essay', '甲於民國（下同）108 年 1 月 1 日犯加重竊盜罪，被法院判處有期徒刑
2 年，於同年 9 月 25 日判決確定，並於同年 10 月 1 日入監執行，一年
後經假釋於 109 年 10 月 6 日釋放離開監獄。甲經釋放出獄數日後，於
109 年 10 月 15 日故意傷害乙，試問是否可以撤銷甲之假釋？甲所犯之
後罪是否可以論以累犯而加重其刑？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:00+00:00", "source_pdf_sha1": "e5e1392aeec0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00137', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '依司法院大法官解釋意旨，關於大學教師之升等評審程序，下列敘述何者正確？', '["基於大學自治，有關大學教師升等資格之審查，立法者不得為任何規定", "基於大學自治，對於升等決定不服之教師，不得提起行政訴訟", "大學教師升等資格之審查，涉及工作權之保障", "教師升等資格評審程序之目的在於維持學術研究與教學之品質，不受教育主管機關監督"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:01+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00138', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '有關監察權之行使，下列敘述何者錯誤？', '["監察院僅得對行政院及其有關部會提出糾正案", "監察委員對行政院及各部會行使之調查權範圍，僅限於調閱文件", "監察院院長對於彈劾案不得指使與干涉", "監察院院長對於糾舉案不得指使與干涉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:01+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00139', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '下列何者並非司法院釋字第499號解釋所列舉之修憲界限？', '["憲法第1條所樹立之民主共和國原則", "憲法第2條之國民主權原則", "憲法第2章所保障之各項人民基本權利", "憲法第13章所明定之基本國策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:01+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00140', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '依憲法增修條文第10條第8項規定，國家就社會救助和國民就業，應優先編列下列何種支出？', '["一般性支出", "資本性支出", "救濟性支出", "政策性支出"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:01+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00141', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '依憲法第8條第1項之規定，司法或警察機關依法定程序，得逮捕拘禁人民。關於本項規定之司法機關與警 察機關，下列敘述何者正確？', '["司法機關包括檢察機關，警察機關不限於組織法上之形式意義警察機關", "司法機關包括檢察機關，警察機關限於組織法上之形式意義警察機關", "司法機關不包括檢察機關，警察機關不限於組織法上之形式意義警察機關", "司法機關不包括檢察機關，警察機關限於組織法上之形式意義警察機關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:01+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00142', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '有關憲法第7條平等原則之敘述，下列何者正確？', '["平等原則禁止所有法律上的差別待遇", "優惠性差別待遇亦為平等原則所禁止", "基於平等原則，立法者應貫徹體系正義的要求", "平等原則僅拘束立法者，不拘束行政機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:01+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00143', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-6ed013db', 'sub-aboriginal-7fec267e-07', NULL, 'single_choice', '依司法院大法官解釋，下列何者違反憲法第13條保障之宗教信仰自由？', '["總統接見宗教領袖", "總統以私人名義參加宗教活動", "設立國教", "核准宗教團體設立學校"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:01+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL)
